function exImgs(name) {
  var base = EX_IMG[name] ? [EX_IMG[name]] : [];
  var extra = EX_EXTRA_IMG[name] || [];
  return base.concat(extra);
}

function warmupImgSrc(item) {
  if (!item) return null;
  if (item.img && WS_IMG[item.img]) return WS_IMG[item.img];
  if (item.img && EX_IMG[item.img]) return EX_IMG[item.img];
  if (EX_IMG[item.n]) return EX_IMG[item.n];
  return null;
}

function ytEmbedUrl(url) {
  if (!url) return null;
  var m = url.match(/youtube\.com\/watch\?v=([^&]+)/) || url.match(/youtu\.be\/([^?&]+)/);
  return m ? "https://www.youtube.com/embed/" + m[1] : null;
}


function parseSerie(str) {
  if (!str) return { sets: 3, reps: ["12"] };
  var m = str.replace(/\s/g, "").match(/(\d+)[xX](.+)/);
  if (!m) return { sets: 3, reps: ["12"] };
  return { sets: parseInt(m[1]), reps: m[2] === "max" ? Array(parseInt(m[1])).fill("max") : m[2].split("-") };
}
function todayStr() { return new Date().toISOString().split("T")[0]; }
var MAX_PROGRESS_EX = ["Push-Up","Trazioni Supine"];
var ACCESSORY_PROGRESS_EX = ["Squat Bulgaro","Face Pull","Curl Bicipiti","Hyperextension con Sacco","Fitball Hamstring Curl","Tricipiti Cavo"];
var CORE_PROGRESS_EX = ["Slackline","Ab Wheel"];
var CARDIO_KIND_LABEL = { run: "Corsa", ruck: "Rucking", hiit: "HIIT", circuit: "Circuito" };
var CALIBRATION_BODYWEIGHT_EX = ["Push-Up","Trazioni","Trazioni Supine","Dip alle Parallele","Nordic Curl","Slackline","Ab Wheel","Fitball Hamstring Curl"];
var CALIBRATION_SKIP_EX = ["HIIT tapis roulant","Rucking con zaino 15-20 kg","Circuito sacco + corde + slackline","Corsa leggera zona 2"];

function usesElasticScale(exName) {
  return exName === "Trazioni" || exName === "Trazioni Supine" || exName === "Dip alle Parallele";
}

function clampElasticTick(v) {
  var n = parseInt(v);
  if (!n) return 0;
  return Math.max(1, Math.min(10, n));
}

function formatElasticTick(v) {
  var n = clampElasticTick(v);
  return n ? ("tacca elastico " + n) : "";
}

function formatLoadAndReps(exName, w, r) {
  var reps = (r === "max" ? "max" : (parseInt(r) || 0)) + " rip";
  if (usesElasticScale(exName)) {
    var tick = formatElasticTick(w);
    return tick ? (tick + " × " + reps) : reps;
  }
  var kg = parseFloat(w) || 0;
  return kg > 0 ? (kg + " kg × " + reps) : reps;
}

function normalizeRirValue(v) {
  if (v == null || v === "") return "";
  if (String(v) === "4+") return "4+";
  var n = parseInt(v);
  if (!isFinite(n)) return "";
  return String(Math.max(0, Math.min(4, n)));
}

function numericRirValue(v) {
  if (v == null || v === "") return null;
  if (String(v) === "4+") return 4;
  var n = parseInt(v);
  return isFinite(n) ? n : null;
}

function formatSetResult(exName, setEntry, isBW, isTime) {
  if (!setEntry) return "";
  var base = isTime
    ? ((setEntry.r === "max" ? "max" : (parseInt(setEntry.r) || 0)) + " s")
    : (isBW ? (setEntry.r + " rip") : formatLoadAndReps(exName, setEntry.w, setEntry.r));
  var rir = normalizeRirValue(setEntry.rir);
  return rir ? (base + " · RIR " + rir) : base;
}

function daysBetweenISO(a, b) {
  if (!a || !b) return null;
  var da = new Date(a + "T00:00:00");
  var db = new Date(b + "T00:00:00");
  return Math.round((db - da) / 86400000);
}

function getCalibrationType(exName, serie) {
  if (CALIBRATION_SKIP_EX.indexOf(exName) >= 0) return "none";
  if (exName === "Slackline") return "tempo";
  if (exName === "Nordic Curl") return "assistito";
  if (exName === "Ab Wheel" || exName === "Fitball Hamstring Curl") return "body-control";
  if (usesElasticScale(exName)) return "band-assist";
  if (CALIBRATION_BODYWEIGHT_EX.indexOf(exName) >= 0 || (serie || "").toLowerCase().indexOf("max") >= 0) return "bodyweight";
  if (exName.indexOf("Cavo") >= 0 || exName === "Face Pull" || exName === "Woodchop") return "cable";
  if (exName === "Squat Bulgaro" || exName === "Stacco Rumeno" || exName === "Affondi" || exName === "Curl Bicipiti") return "dumbbell";
  return "weighted";
}

function getCalibrationQuickInstruction(exName, serie) {
  var type = getCalibrationType(exName, serie);
  if (type === "none") return "Questo esercizio non richiede calibrazione del peso.";
  if (type === "band-assist") return "Qui non usi kg: salva la tacca dell'elastico da 1 (massimo aiuto) a 10 (minimo aiuto). Se resti sotto il minimo del range, serve piu aiuto.";
  if (type === "bodyweight") return "Segna quante ripetizioni pulite fai fermandoti con circa 1-2 ripetizioni in riserva. Questo numero diventa il tuo punto zero.";
  if (type === "assistito") return "Trova il livello di assistenza con cui controlli bene il movimento. Se la discesa e incontrollata, aumenta l'assistenza.";
  if (type === "tempo") return "Verifica se riesci a completare il tempo previsto con controllo. Se e facile, annotalo e aumenta la difficolta in futuro.";
  if (type === "body-control") return "Trova il range di movimento o la variante che riesci a controllare bene. Conta solo le ripetizioni pulite.";
  return "Fai una prima serie di test e valuta quante ripetizioni pulite ti restavano. Se erano 2, hai trovato il peso giusto.";
}

function getCalibrationRestLabel(exName, rec) {
  if (rec) return "Riposa " + String(rec).toLowerCase() + ".";
  var heavy = ["Squat","Stacco da Terra","Panca","Military Press","Trazioni","Trazioni Supine","Front Squat","Pause Squat","Push Press","Stacco Sumo","Stacco Rumeno","Hip Thrust Bilanciere","T-bar Row","Dip alle Parallele"];
  var medium = ["Rematore Bilanciere","Rematore Manubri","Nordic Curl","Good Morning","Hyperextension","Affondi","Squat Bulgaro","Pendlay Row","Walking Lunge","Push-Up","Floor Press Manubri","Push-Up Declino","Hyperextension con Sacco","Fitball Hamstring Curl","Face Pull","Alzate Laterali","French Press Manubri"];
  if (heavy.indexOf(exName) >= 0) return "Riposa 2 minuti.";
  if (medium.indexOf(exName) >= 0) return "Riposa 90 secondi.";
  return "Riposa come da recupero previsto per questo esercizio.";
}

function isFatiguePatternAtTop(reps, spec) {
  if (!spec || spec.kind !== "range" || !reps || reps.length < 4) return false;
  var half = Math.floor(reps.length / 2);
  var firstHalfTop = reps.slice(0, half).every(function(r) { return r >= spec.max; });
  var secondHalfInRangeBelowTop = reps.slice(half).every(function(r) { return r >= spec.min && r < spec.max; });
  return firstHalfTop && secondHalfInRangeBelowTop;
}

function getCalibrationChangeLabel(type, dir) {
  if (type === "cable") return dir === "up" ? "sali di uno step al cavo" : "scendi di uno step al cavo";
  if (type === "dumbbell") return dir === "up" ? "aumenta di poco il carico" : "riduci di poco il carico";
  return dir === "up" ? "aumenta il carico" : "riduci il carico";
}

function getCalibrationRetestHint(meta) {
  if (!meta || !meta.isLastSet) return meta ? getCalibrationRestLabel(meta.exName, meta.rec) + " Poi rifai la serie di test." : "Rifai la serie di test.";
  return "Questa era l'ultima serie prevista: segna l'indicazione e correggi il carico dalla prossima seduta, senza rifare tutto da capo oggi.";
}

function formatEffortLabel(rpe, serie) {
  if (!rpe) return "";
  var raw = String(rpe).trim();
  if (!raw) return "";
  if ((serie || "").toUpperCase().indexOf("RIR") >= 0) return raw;
  return "RPE " + raw;
}

function getCalibrationDecision(type, reserve, cleanReps, serie, exName, meta) {
  var val = reserve === "4+" ? 4 : parseInt(reserve);
  var spec = parseProgressSpec(serie);
  var clean = parseInt(cleanReps) || 0;
  if (type === "band-assist") {
    if (spec && spec.kind === "range" && clean < spec.min) {
      return {
        tone: "hold",
        title: "Aiuto insufficiente",
        detail: clean <= Math.max(1, spec.min - 3)
          ? "Sei troppo sotto il minimo del range per questa tacca. Usa piu assistenza: scendi di 1-2 tacche. " + getCalibrationRetestHint(meta)
          : "Sei sotto il minimo del range. Usa un po' piu assistenza: scendi di 1 tacca. " + getCalibrationRetestHint(meta),
        accepted: false,
      };
    }
    if (val >= 3) return { tone: "mid", title: "Un po' troppo facile", detail: "Puoi usare meno aiuto: sali di 1 tacca. " + getCalibrationRetestHint(meta), accepted: false };
    if (val === 2) return { tone: "up", title: "Tacca giusta", detail: "Salva questa tacca dell'elastico: e il tuo riferimento di partenza.", accepted: true };
    if (val === 1) return { tone: "up", title: "Tacca valida", detail: "Va bene anche cosi. Sei nella zona alta, ma il riferimento e utile.", accepted: true };
    return { tone: "hold", title: "Troppo vicino al cedimento", detail: "Serve piu aiuto: scendi di 1 tacca. " + getCalibrationRetestHint(meta), accepted: false };
  }
  if ((type === "bodyweight" || type === "assistito" || type === "body-control") && spec && spec.kind === "range" && clean < spec.min) {
    return {
      tone: "hold",
      title: "Difficolta troppo alta",
      detail: "Sei sotto il minimo del range. Usa una variante piu facile o piu assistenza prima di salvare questo punto zero.",
      accepted: false,
    };
  }
  if (type === "bodyweight" || type === "assistito" || type === "tempo" || type === "body-control") {
    if (val >= 3) return { tone: "mid", title: "Un po' troppo facile", detail: "La prossima volta puoi spingere 1-2 ripetizioni in piu o aumentare leggermente la difficolta.", accepted: false };
    if (val === 2) return { tone: "up", title: "Punto zero corretto", detail: "Salva questo numero: e il tuo riferimento di partenza.", accepted: true };
    if (val === 1) return { tone: "up", title: "Punto zero valido", detail: "Va bene anche cosi. Sei nella zona alta, ma il riferimento e utile.", accepted: true };
    return { tone: "hold", title: "Troppo vicino al cedimento", detail: "La prossima volta fermati 1 ripetizione prima o usa una variante piu facile.", accepted: false };
  }
  if (spec && spec.kind === "range" && clean < spec.min) {
    return {
      tone: "hold",
      title: "Peso troppo pesante",
      detail: clean <= Math.max(1, spec.min - 3)
        ? "Sei troppo sotto il minimo del range: " + getCalibrationChangeLabel(type, "down") + " in modo netto. " + getCalibrationRetestHint(meta)
        : "Sei sotto il minimo del range: " + getCalibrationChangeLabel(type, "down") + ". " + getCalibrationRetestHint(meta),
      accepted: false,
    };
  }
  if (reserve === "4+") return { tone: "hold", title: "Peso troppo leggero", detail: getCalibrationChangeLabel(type, "up") + " in modo deciso. " + getCalibrationRetestHint(meta), accepted: false };
  if (val === 3) return { tone: "mid", title: "Leggermente leggero", detail: getCalibrationChangeLabel(type, "up") + ". " + getCalibrationRetestHint(meta), accepted: false };
  if (val === 2) return { tone: "up", title: "Peso giusto", detail: "Completa le serie rimanenti con questo peso. Questo e il tuo punto di partenza.", accepted: true };
  if (val === 1) return { tone: "up", title: "Peso giusto, zona alta", detail: "Va bene per iniziare. Tieni questo peso e completa le serie rimanenti.", accepted: true };
  return { tone: "hold", title: "Peso troppo pesante", detail: getCalibrationChangeLabel(type, "down") + ". " + getCalibrationRetestHint(meta), accepted: false };
}

function safeCalibrationDecision(type, reserve, cleanReps, serie, exName, meta) {
  var safeType = type || getCalibrationType(exName, serie) || "weighted";
  var safeReserve = String(reserve || "2");
  var safeClean = Math.max(0, parseInt(cleanReps) || 0);
  var spec = null;
  try { spec = parseProgressSpec(serie); } catch (_) { spec = null; }
  if (safeClean <= 0) {
    return {
      tone: "hold",
      title: "Dati incompleti",
      detail: "Inserisci almeno 1 ripetizione pulita prima di salvare.",
      accepted: false,
    };
  }
  if (safeType === "none") {
    return { tone: "up", title: "Serie salvabile", detail: "Questo esercizio non richiede calibrazione del peso.", accepted: true };
  }
  if (safeType === "band-assist") {
    if (spec && spec.kind === "range" && safeClean < spec.min) {
      return { tone: "hold", title: "Serve piu aiuto", detail: "Sei sotto il minimo del range: usa una tacca con piu assistenza. " + getCalibrationRetestHint(meta), accepted: false };
    }
    if (safeReserve === "4+" || safeReserve === "3") {
      return { tone: "mid", title: "Troppo facile", detail: "Puoi usare meno aiuto: sali di 1 tacca. " + getCalibrationRetestHint(meta), accepted: false };
    }
    if (safeReserve === "2" || safeReserve === "1") {
      return { tone: "up", title: "Tacca giusta", detail: "Salva questa tacca dell'elastico come riferimento.", accepted: true };
    }
    return { tone: "hold", title: "Troppo vicino al cedimento", detail: "Serve piu aiuto: scendi di 1 tacca. " + getCalibrationRetestHint(meta), accepted: false };
  }
  if (safeType === "bodyweight" || safeType === "assistito" || safeType === "tempo" || safeType === "body-control") {
    if (spec && spec.kind === "range" && safeClean < spec.min) {
      return { tone: "hold", title: "Difficolta troppo alta", detail: "Sei sotto il minimo del range. Usa una variante piu facile o piu assistenza.", accepted: false };
    }
    if (spec && spec.kind === "range" && safeClean > spec.max) {
      return { tone: "mid", title: "Troppo facile per partire", detail: "Se il target e " + spec.min + "-" + spec.max + " e tu arrivi gia a " + safeClean + ", la difficolta e troppo bassa per una calibrazione utile. Aumenta la difficolta o riduci l'assistenza.", accepted: false };
    }
    if (spec && spec.kind === "range" && safeClean > spec.min && (safeReserve === "2" || safeReserve === "3" || safeReserve === "4+")) {
      return { tone: "mid", title: "Partenza troppo facile", detail: "In calibrazione il riferimento dovrebbe stare vicino al numero basso del range. Se sei gia oltre (" + safeClean + " su " + spec.min + "-" + spec.max + ") con ancora margine, aumenta leggermente la difficolta.", accepted: false };
    }
    if (safeReserve === "4+" || safeReserve === "3") {
      return { tone: "mid", title: "Un po' troppo facile", detail: "La prossima volta puoi aumentare leggermente la difficolta o fare piu ripetizioni.", accepted: false };
    }
    if (safeReserve === "2" || safeReserve === "1") {
      return { tone: "up", title: "Punto zero corretto", detail: "Salva questo riferimento come base di partenza.", accepted: true };
    }
    return { tone: "hold", title: "Troppo vicino al cedimento", detail: "La prossima volta fermati un po' prima o alleggerisci la variante.", accepted: false };
  }
  if (spec && spec.kind === "range" && safeClean < spec.min) {
    return { tone: "hold", title: "Peso troppo pesante", detail: "Sei sotto il minimo del range: " + getCalibrationChangeLabel(safeType, "down") + ". " + getCalibrationRetestHint(meta), accepted: false };
  }
  if (spec && spec.kind === "range" && safeClean > spec.max) {
    return {
      tone: "mid",
      title: "Peso troppo basso",
      detail: "Se il target e " + spec.min + "-" + spec.max + " e tu arrivi gia a " + safeClean + ", questo carico e troppo facile per una calibrazione utile. " + getCalibrationChangeLabel(safeType, "up") + ". " + getCalibrationRetestHint(meta),
      accepted: false
    };
  }
  if (spec && spec.kind === "range" && safeClean > spec.min && (safeReserve === "2" || safeReserve === "3" || safeReserve === "4+")) {
    return {
      tone: "mid",
      title: "Peso troppo leggero per partire",
      detail: "In calibrazione devi trovare un riferimento vicino al numero basso del range. Se fai gia " + safeClean + " rip su " + spec.min + "-" + spec.max + " con ancora margine, " + getCalibrationChangeLabel(safeType, "up") + ". " + getCalibrationRetestHint(meta),
      accepted: false
    };
  }
  if (safeReserve === "4+") {
    return { tone: "hold", title: "Peso troppo leggero", detail: getCalibrationChangeLabel(safeType, "up") + " in modo deciso. " + getCalibrationRetestHint(meta), accepted: false };
  }
  if (safeReserve === "3") {
    return { tone: "mid", title: "Leggermente leggero", detail: getCalibrationChangeLabel(safeType, "up") + ". " + getCalibrationRetestHint(meta), accepted: false };
  }
  if (safeReserve === "2") {
    return { tone: "up", title: "Peso giusto", detail: "Completa le serie rimanenti con questo riferimento. Questo e il tuo punto di partenza.", accepted: true };
  }
  if (safeReserve === "1") {
    return { tone: "up", title: "Peso giusto, zona alta", detail: "Va bene per iniziare. Tieni questo riferimento e completa le serie rimanenti.", accepted: true };
  }
  return { tone: "hold", title: "Peso troppo pesante", detail: getCalibrationChangeLabel(safeType, "down") + ". " + getCalibrationRetestHint(meta), accepted: false };
}

function cardioOptionKind(opt) {
  var label = (opt && opt.label ? opt.label : "").toLowerCase();
  if (label.indexOf("rucking") >= 0) return "ruck";
  if (label.indexOf("corsa") >= 0) return "run";
  if (label.indexOf("hiit") >= 0) return "hiit";
  if (label.indexOf("circuito") >= 0) return "circuit";
  return "cardio";
}

function cardioFieldConfig(kind) {
  if (kind === "ruck") return [
    { key: "minutes", label: "Min", placeholder: "60", inputMode: "numeric" },
    { key: "km", label: "Km", placeholder: "5.2", inputMode: "decimal" },
    { key: "kg", label: "Kg zaino", placeholder: "16", inputMode: "decimal" },
  ];
  if (kind === "run") return [
    { key: "minutes", label: "Min", placeholder: "30", inputMode: "numeric" },
    { key: "km", label: "Km", placeholder: "5.0", inputMode: "decimal" },
  ];
  return [
    { key: "minutes", label: "Min", placeholder: "25", inputMode: "numeric" },
  ];
}

